diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index c06d5c759634..93ca15d9f025 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -739,6 +739,50 @@ Value *InstCombinerImpl::simplifyRangeCheck(ICmpInst *Cmp0, ICmpInst *Cmp1,
   return Builder.CreateICmp(NewPred, Input, RangeEnd);
 }

+// Fold (x != C) & (x + (-C) <= y) -> (x + (-C - 1) < y)
+// This pattern checks that x + (-C) doesn't wrap incorrectly when x == C.
+// When x != C, x + (-C) correctly computes the unsigned difference, and
+// (x + (-C) <= y) combined with x != C is equivalent to (x + (-C - 1) < y).
+// Special case: (x != -1) & (x + 1 <= y) -> x < y
+static Value *foldICmpNeAddConstantULE(ICmpInst *Cmp0, ICmpInst *Cmp1,
+                                       InstCombiner::BuilderTy &Builder) {
+  // Check for x != C
+  if (Cmp0->getPredicate() != ICmpInst::ICMP_NE)
+    return nullptr;
+  const APInt *C;
+  if (!match(Cmp0->getOperand(1), m_APInt(C)))
+    return nullptr;
+
+  Value *X = Cmp0->getOperand(0);
+
+  // Check for (X + (-C)) <= Y where X is the same variable
+  const APInt *AddC;
+  if (!match(Cmp1->getOperand(0), m_Add(m_Specific(X), m_APInt(AddC))))
+    return nullptr;
+
+  // Add constant must be -C (negation of C)
+  if (*AddC != -*C)
+    return nullptr;
+
+  // Must be unsigned less-or-equal comparison
+  if (Cmp1->getPredicate() != ICmpInst::ICMP_ULE)
+    return nullptr;
+
+  // (X != C) & (X + (-C) <= Y) -> (X + (-C - 1) < Y)
+  Value *Y = Cmp1->getOperand(1);
+  Type *Ty = Cmp0->getType();
+  APInt NewAddC = -*C - 1;
+  
+  if (NewAddC.isZero()) {
+    // (X + 0 < Y) -> (X < Y)
+    return Builder.CreateICmp(ICmpInst::ICMP_ULT, X, Y);
+  }
+  return Builder.CreateICmp(ICmpInst::ICMP_ULT,
+                            Builder.CreateAdd(X, ConstantInt::get(Ty, NewAddC)),
+                            Y);
+}
+
+
 // Fold (iszero(A & K1) | iszero(A & K2)) -> (A & (K1 | K2)) != (K1 | K2)
 // Fold (!iszero(A & K1) & !iszero(A & K2)) -> (A & (K1 | K2)) == (K1 | K2)
 Value *InstCombinerImpl::foldAndOrOfICmpsOfAndWithPow2(ICmpInst *LHS,
@@ -3077,6 +3121,11 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   // TODO: One of these directions is fine with logical and/or, the other could
   // be supported by inserting freeze.
   if (!IsLogical) {
+    // (x != -1) & (x + 1 <= y) -> x < y
+    if (Value *V = foldICmpNeAddConstantULE(LHS, RHS, Builder))
+      return V;
+    if (Value *V = foldICmpNeAddConstantULE(RHS, LHS, Builder))
+      return V;
     // E.g. (icmp slt x, 0) | (icmp sgt x, n) --> icmp ugt x, n
     // E.g. (icmp sge x, 0) & (icmp slt x, n) --> icmp ult x, n
     if (Value *V = simplifyRangeCheck(LHS, RHS, /*Inverted=*/!IsAnd))

